var findDiagonalOrder = function(nums) {
    const diag = new Map();
    for (let i = 0; i < nums.length; i++) {
        for (let j = 0; j < nums[i].length; j++) {
            const key = i + j;
            if (!diag.has(key)) diag.set(key, []);
            diag.get(key).push([i, nums[i][j]]);
        }
    }
    const keys = [...diag.keys()].sort((a, b) => a - b);
    const result = [];
    for (const key of keys) {
        const group = diag.get(key).sort((a, b) => b[0] - a[0]);
        for (const [, val] of group) result.push(val);
    }
    return result;
};
